74	
75	    if {$MGC_fix_antenna_use_diodes eq true} {
76		if {$MGC_fix_antenna_diodes != ""} {
77		    config_antenna -diodes $MGC_fix_antenna_diodes
78		}
79		fix_antenna -method diode -finish all
80	    }
81	}
82	
83	## Check if design is DRC clean before starting chip finishing
84	set MGC_num_drc_errors_threshold 100    ; # If number of DRC errors exceeds this threshold the chip finishing steps will not be performed
85	check_drc
86	set num0 [llength [get_objects -type error -filter @category==drc -quiet true]]
87	set skip_chip_finishing false
88	if { $num0 > $MGC_num_drc_errors_threshold } {
89	    fk_msg -type info "Number of DRC (including antenna) errors is too high ($num0 > $MGC_num_drc_errors_threshold). Chip finishing steps will be skipped \n"
90	    set skip_chip_finishing true
91	}
